class Solution:
    def maximumPopulation(self, logs):
        best_year = 1950
        best_pop = -1
        for y in range(1950, 2051):
            pop = sum(1 for b, d in logs if b <= y < d)
            if pop > best_pop:
                best_pop = pop
                best_year = y
        return best_year

