class Solution:
    def maximumPopulation(self, logs):
        delta = [0] * 2052
        for b, d in logs:
            delta[b] += 1
            delta[d] -= 1
        best_year = 1950
        best_pop = -1
        cur = 0
        for y in range(1950, 2051):
            cur += delta[y]
            if cur > best_pop:
                best_pop = cur
                best_year = y
        return best_year

