var maximumPopulation = function(logs) {
    const delta = new Array(2052).fill(0);
    for (const [b, d] of logs) { delta[b]++; delta[d]--; }
    let bestYear = 1950, bestPop = -1, cur = 0;
    for (let y = 1950; y <= 2050; y++) {
        cur += delta[y];
        if (cur > bestPop) { bestPop = cur; bestYear = y; }
    }
    return bestYear;
};
